#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; long long x1,x2,x3,x4,x5,x6;
        scanf("%lld %lld %lld %lld %lld %lld %lld", &N, &x1,&x2,&x3,&x4,&x5,&x6);
        long long sum = x1+x2+x3+x4+x5+x6;
        long long liters = (N + 1) / 2; // ceil(N/2)
        long long ans = sum * liters;
        printf("%lld\n", ans);
    }
    return 0;
}

